export function getLanguageAlphabet(lang: LanguageName): string[] {
  if (lang === "简体中文") {
    const gbBlock = STANDARD_BLOCKS.find((b) => b.id === "gb2312");
    return gbBlock ? getCharsForBlock(gbBlock) : [];
  }
  if (lang === "繁体中文" || lang === "香港繁体" || lang === "澳门繁体") {
    const big5Block = STANDARD_BLOCKS.find((b) => b.id === "big5");
    return big5Block ? getCharsForBlock(big5Block) : [];
  }
  return LANGUAGE_ALPHABETS[lang] || [];
}

export function getCountryAlphabet(countryName: CountryName): string[] {
  const metadata = COUNTRY_METADATA[countryName];
  if (!metadata) return [];
  const alphabets = metadata.languages.flatMap((lang) => getLanguageAlphabet(lang));
  return Array.from(new Set(alphabets));
}

export interface CountryCoverageStatusResult {
  coverage: number;
  status: string; // "完全可用" | "基本可用" | "不可用"
  supportedCount: number;
  totalCount: number;
}

function getBlockCoverageOfSet(blockId: string, supportedChars: Set<number>) {
  if (blockId === "japanese-kana") {
    let supportedCount = 0;
    for (let c = 0x3040; c <= 0x309F; c++) {
      if (supportedChars.has(c)) supportedCount++;
    }
    for (let c = 0x30A0; c <= 0x30FF; c++) {
      if (supportedChars.has(c)) supportedCount++;
    }
    const finalSupported = Math.min(189, supportedCount);
    return {
      coverage: finalSupported / 189,
      supportedCount: finalSupported,
      totalCount: 189,
    };
  }

  const block = STANDARD_BLOCKS.find((b) => b.id === blockId);
  if (!block) return { coverage: 0, supportedCount: 0, totalCount: 0 };
  const chars = getCharsForBlock(block);
  if (chars.length === 0) return { coverage: 0, supportedCount: 0, totalCount: 0 };

  let supportedCount = 0;
  for (const char of chars) {
    let isSup = true;
    for (let i = 0; i < char.length; i++) {
      if (!supportedChars.has(char.codePointAt(i)!)) {
        isSup = false;
        break;
      }
    }
    if (isSup) supportedCount++;
  }

  return {
    coverage: supportedCount / chars.length,
    supportedCount,
    totalCount: chars.length,
  };
}

function getCoverageLevel(cov: number): number {
  if (cov >= 0.98) return 3; // 完全可用
  if (cov >= 0.95) return 2; // 基本可用
  return 1; // 不可用
}

function getStatusName(level: number): string {
  if (level === 3) return "完全可用";
  if (level === 2) return "基本可用";
  return "不可用";
}

export function evaluateCountryCoverageAndStatus(
  countryName: string,
  supportedChars: Set<number>,
): CountryCoverageStatusResult {
  const isCn = countryName === "中国";
  const isTwHkMo = ["中国台湾", "中国香港", "中国澳门"].includes(countryName);
  const isJp = countryName === "日本";
  const isKr = ["韩国", "朝鲜", "韩国/朝鲜"].includes(countryName);

  if (isCn) {
    const standards = [
      { id: "gb18030-level3", name: "GB18030-2022级别3" },
      { id: "gb18030-level2", name: "GB18030-2022级别2" },
      { id: "gb18030-level1", name: "GB18030-2022级别1" },
      { id: "gb2312", name: "GB2312" },
    ];

    let bestOption: { id: string; name: string; level: number; coverage: number; supportedCount: number; totalCount: number } | null = null;

    for (const std of standards) {
      const covInfo = getBlockCoverageOfSet(std.id, supportedChars);
      const level = getCoverageLevel(covInfo.coverage);

      if (!bestOption || level > bestOption.level) {
        bestOption = {
          id: std.id,
          name: std.name,
          level,
          coverage: covInfo.coverage,
          supportedCount: covInfo.supportedCount,
          totalCount: covInfo.totalCount,
        };
      }
    }

    if (bestOption) {
      const statusName = getStatusName(bestOption.level);
      return {
        coverage: bestOption.coverage,
        status: statusName === "不可用" ? statusName : `${statusName}【满足${bestOption.name}标准】`,
        supportedCount: bestOption.supportedCount,
        totalCount: bestOption.totalCount,
      };
    }
  }

  if (isTwHkMo) {
    const covInfo = getBlockCoverageOfSet("big5", supportedChars);
    const level = getCoverageLevel(covInfo.coverage);
    const statusName = getStatusName(level);
    return {
      coverage: covInfo.coverage,
      status: statusName === "不可用" ? statusName : `${statusName}【满足BIG5标准】`,
      supportedCount: covInfo.supportedCount,
      totalCount: covInfo.totalCount,
    };
  }

  if (isJp) {
    const kanaCovInfo = getBlockCoverageOfSet("japanese-kana", supportedChars);
    if (kanaCovInfo.coverage < 0.95) {
      return {
        coverage: kanaCovInfo.coverage,
        status: "不可用",
        supportedCount: kanaCovInfo.supportedCount,
        totalCount: kanaCovInfo.totalCount,
      };
    }

    const standards = [
      { id: "jis-x-0208-level2", name: "JISX0208第二水准" },
      { id: "jis-x-0208-level1", name: "JISX0208第一水准" },
      { id: "joyo-kanji", name: "日本常用汉字集" },
    ];

    let bestOption: { id: string; name: string; level: number; coverage: number; supportedCount: number; totalCount: number } | null = null;

    for (const std of standards) {
      const covInfo = getBlockCoverageOfSet(std.id, supportedChars);
      const level = getCoverageLevel(covInfo.coverage);

      if (!bestOption || level > bestOption.level) {
        bestOption = {
          id: std.id,
          name: std.name,
          level,
          coverage: covInfo.coverage,
          supportedCount: covInfo.supportedCount,
          totalCount: covInfo.totalCount,
        };
      }
    }

    if (bestOption) {
      const statusName = getStatusName(bestOption.level);
      return {
        coverage: bestOption.coverage,
        status: `${statusName}【满足${bestOption.name}标准】`,
        supportedCount: bestOption.supportedCount,
        totalCount: bestOption.totalCount,
      };
    }
  }

  if (isKr) {
    const covInfo = getBlockCoverageOfSet("ks-x-1001", supportedChars);
    const level = getCoverageLevel(covInfo.coverage);
    const statusName = getStatusName(level);
    return {
      coverage: covInfo.coverage,
      status: `${statusName}【满足KS X 1001标准】`,
      supportedCount: covInfo.supportedCount,
      totalCount: covInfo.totalCount,
    };
  }

  const metadata = COUNTRY_METADATA[countryName];
  if (!metadata || !metadata.languages || metadata.languages.length === 0) {
    return { coverage: 0, status: "未知", supportedCount: 0, totalCount: 0 };
  }

  const results = metadata.languages.map((lang) => {
    const alphabet = getLanguageAlphabet(lang);
    let supported = 0;
    for (const char of alphabet) {
      let isSup = true;
      for (let i = 0; i < char.length; i++) {
        if (!supportedChars.has(char.codePointAt(i)!)) {
          isSup = false;
          break;
        }
      }
      if (isSup) supported++;
    }
    const cov = alphabet.length > 0 ? supported / alphabet.length : 0;
    return {
      coverage: cov,
      supportedCount: supported,
      totalCount: alphabet.length,
      level: getCoverageLevel(cov),
    };
  });

  // Take the best one
  let best = results[0];
  for (const res of results) {
    if (res.level > best.level) {
      best = res;
    } else if (res.level === best.level && res.coverage > best.coverage) {
      best = res;
    }
  }

  const status = getStatusName(best.level);

  return {
    coverage: best.coverage,
    status,
    supportedCount: best.supportedCount,
    totalCount: best.totalCount,
  };
}

// Ensure lazy properties exist on LANGUAGE_ALPHABETS
if (!LANGUAGE_ALPHABETS["简体中文"]) {
  Object.defineProperty(LANGUAGE_ALPHABETS, "简体中文", {
    get() {
      const gbBlock = STANDARD_BLOCKS.find((b) => b.id === "gb2312");
      return gbBlock ? getCharsForBlock(gbBlock) : [];
    },
    configurable: true,
    enumerable: true,
  });
}
if (!LANGUAGE_ALPHABETS["繁体中文"]) {
  Object.defineProperty(LANGUAGE_ALPHABETS, "繁体中文", {
    get() {
      const big5Block = STANDARD_BLOCKS.find((b) => b.id === "big5");
      return big5Block ? getCharsForBlock(big5Block) : [];
    },
    configurable: true,
    enumerable: true,
  });
}
if (!LANGUAGE_ALPHABETS["注音"]) {
  Object.defineProperty(LANGUAGE_ALPHABETS, "注音", {
    get() {
      // Bopomofo is in UNICODE_BLOCKS
      const block = UNICODE_BLOCKS.find((b: any) => b.id === "bopomofo");
      return block ? getCharsForBlock(block) : [];
    },
    configurable: true,
    enumerable: true,
  });
}
